"""
MKT Original Commentary — Hosea chapters 7–12
Run: python3 scripts/zc-original-hosea-7-12.py

Ch 11 v1 already exists (from bulk script). All other verses missing.
Key terms:
  chesed (covenant loyalty/steadfast love), teshuvah (return/repentance),
  da'at elohim (knowledge of God), nabi (prophet), tannur (oven),
  ruach/suphah (wind/whirlwind), qeshet remiyah (treacherous bow)
Notable: 10:8 cited in Luke 23:30 / Rev 6:16; 11:8-9 peak of divine pathos;
  12:3-4 Jacob at Peniel
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HOSEA = {
  "7": {
    "1": "<p><strong>kerof'i leYisrael nigla avon Efraim veraot Shomron</strong>: 'When I would have healed Israel, the iniquity of Ephraim was exposed.' <em>Rapha</em> (heal) is the covenantal restoration verb — YHWH as healer of the covenant people's sins is developed throughout the prophets (Jer 3:22; 17:14; 33:6; Isa 53:5). The divine healing intention is frustrated not by divine incapacity but by the exposure of sin: <em>nigla</em> (was revealed, laid bare). The metaphor is clinical: YHWH approaches to heal; the wound's true nature is exposed; the patient refuses treatment. Samaria's sin is not private — it is exposed in the public record of 'theft and banditry within' (<em>beqirbo</em>, within it/within the house). The domestic and civic corruption are as visible to YHWH as if laid on an examining table.</p>",
    "2": "<p><strong>velo yomeru lilevavam kol ra'atam zakarti</strong>: 'But they do not consider in their hearts that I remember all their evil.' <em>Zakar</em> (remember) functions in the OT as judicial memory — YHWH's remembering is not passive recall but active prosecution. The community's self-delusion is the failure to apply <em>zakar</em> to themselves: they do not reckon with the fact that YHWH's memory is comprehensive and will produce judgment. Their deeds surround them (<em>savavum</em>) like witnesses at a trial; they are 'before my face' (<em>neged panai</em>). The forensic imagery — memory, deeds as witnesses, before the face — frames Israel's conduct as a legal case already prepared against them.</p>",
    "3": "<p><strong>bemaltam yesamechu melekh uvechacheshan sarim</strong>: 'They make the king happy with their wickedness, and win the princes with their treachery.' <em>Machale</em> (make happy/rejoice) and <em>kachash</em> (treachery, lying) describe court politics: the royal court is sustained by a system of flattering treachery. Those who succeed in the royal court do so by corrupting the court with wickedness. The system of mutual congratulation in sin (rulers congratulating subjects; subjects congratulating rulers) is the social face of covenant breakdown — when leaders reward wickedness rather than righteousness, the covenant order inverts.</p>",
    "4": "<p><strong>kullam mena'afim kivir bo'er me'ofeh</strong>: 'They are all adulterers, burning like an oven that the baker does not need to stoke.' The oven metaphor (<em>tannur</em>) runs through vv. 4-7 — an oven that burns so intensely it requires no stoking through the night, then erupts by morning. <em>Mena'afim</em> (adulterers) is used in Hosea both literally (sexual unfaithfulness) and theologically (covenant infidelity with Baal). The self-sustaining, unstoked oven describes the autonomous nature of their sin: it does not need external kindling because it has become self-perpetuating. The baker who can sleep while the oven sustains itself = YHWH observing how Israel's sin has achieved its own momentum.</p>",
    "5": "<p><strong>yom malkeinu hechelim sarim chemat minayin</strong>: 'On the day of our king, the princes made themselves sick with wine.' Royal festival days in the ancient Near East involved prescribed feasting; here the feast becomes a scene of royal debauchery in which the princes corrupt the king himself (<em>mashach yado et lotze'im</em>, the king stretches out his hand with scoffers). The king who should model covenant faithfulness becomes instead a fellow traveler with those who mock. The royal feast that should celebrate YHWH's provision becomes a scene of covenant mockery.</p>",
    "6": "<p><strong>ki qirevu chetannur libbam beorvam</strong>: 'For their hearts smolder like an oven as they scheme; their baker sleeps through the night, but in the morning it blazes like a flaming fire.' The conspiracy (<em>orvam</em>, their plotting/lurking) is the thing that keeps the oven of the heart hot through the night of apparent inactivity. While the baker (= the king? the people's patron?) sleeps, the plotters' hearts burn. By morning, the conspiracy erupts into open action. The image captures how political and religious betrayal gestate quietly and then express themselves suddenly — the visible sin has long-prepared invisible roots.</p>",
    "7": "<p><strong>kullam yichammu katannur veyochelu et-shoftehem</strong>: 'They are all as hot as an oven, and they devour their rulers; all their kings have fallen. None of them calls on me.' The political instability of the northern kingdom's final decades (assassinations, rapid turnover of kings) is framed as the logical consequence of the burning conspiracy: those who burn hot enough devour their own leaders. 'None of them calls on me' (<em>ein qore elai mehem</em>) is the theological summary: in the midst of political chaos, no one performs the only action that could address the underlying cause. The religious failure (no calling on YHWH) and the political failure (devouring rulers) are the same crisis at different levels.</p>",
    "8": "<p><strong>Efraim baamim hu yitbolal Efraim hayah ugah bilti hafukah</strong>: 'Ephraim mixes himself among the peoples; Ephraim is a flat cake that has not been turned over.' The <em>ugah</em> (round flat bread) that has not been turned (<em>bilti hafukah</em>) is burned on one side, raw on the other — useless for sustenance. As a description of Ephraim, it means: partially assimilated into foreign cultures, partially still Israelite, but incomplete and unusable in either direction. The mixing (<em>hitbolal</em>) with peoples is the opposite of the covenant distinction that set Israel apart. The metaphor is domestically precise: a half-baked loaf that ruins both the baking and the eating.</p>",
    "9": "<p><strong>achlu zarim kocho vehu lo yeda gam seivah zerukah bo vehu lo yeda</strong>: 'Foreigners have consumed his strength, and he does not know it. Gray hairs are scattered on him, yet he does not know it.' The pathos of 7:9 is the ignorance of decline: Ephraim does not recognize that his vitality is being sapped. <em>Kocho</em> (his strength) is being consumed by foreigners even as he continues in his political and religious routines. The gray hairs are the visible sign of advancing age and weakness that the person himself does not perceive. This is the prophetic diagnosis: the most dangerous condition is not crisis but unrecognized decline, when the patient feels fine while dying.</p>",
    "10": "<p><strong>veyigne ga'on Yisrael befanav</strong>: 'The pride of Israel testifies against him to his face, yet they do not return to the LORD.' <em>Ga'on Yisrael</em> (the pride of Israel) is used in Hosea 5:5 and here: their very pride acts as witness against them. They will not return (<em>lo shavu</em>) to YHWH despite the self-evident testimony of their own failure. <em>Teshuvah</em> (return/repentance) is Hosea's central call — the verb <em>shuv</em> appears repeatedly throughout the book as the prescribed response to the covenant crisis. Its negation here ('they do not return') is the book's central diagnosis: the medicine is available but refused.</p>",
    "11": "<p><strong>vayehi Efraim keyonah pote't ein lev</strong>: 'Ephraim is like a senseless dove, lacking all judgment.' The dove (<em>yonah</em>) flutters between Egypt and Assyria, calling one direction then the other, with no settled policy. <em>Pote't</em> (simple, senseless, easily deceived) describes the bird's inability to evaluate threats — it flies toward danger as readily as safety. Israel's foreign policy of alternating between Egyptian and Assyrian alliances is diagnosed as political senselessness masquerading as strategic flexibility. The dove lacks the wisdom (<em>lev</em>, heart = understanding) to see that neither great power can provide what YHWH alone can give.</p>",
    "12": "<p><strong>ka'asher yelchu efros aleihem reshti</strong>: 'As they go, I will cast my net over them; I will bring them down like the birds of the sky.' The hunting net (<em>reshet</em>) catches the senseless dove of v11 — the very aimless fluttering that the dove does leads it into the net. YHWH's judgment is described as the inevitable consequence of their own trajectory: they fly toward judgment. <em>Yissireim keshema'at ledatam</em> (I will discipline them as their congregation has heard) — the announced covenant curses are now enacted; they are not surprises.</p>",
    "13": "<p><strong>oy lahem ki nadedu mimeni shod lahem ki pasha'u vi</strong>: 'Woe to them, for they have strayed from me! Destruction to them, because they have rebelled against me!' <em>Oy</em> (woe) is the lament-cry that precedes judgment announcements throughout the prophets. Two verbs describe the sin: <em>nadad</em> (stray, wander away, be driven) and <em>pasha</em> (rebel, transgress, breach the covenant relationship). The first suggests drifting; the second suggests active defiance. 'I would redeem them [<em>efdem</em>], yet they speak lies against me' — YHWH's intention to redeem is present even in the woe-oracle; the obstacle is their lying, not his willingness. <em>Padah</em> (redeem/ransom) is the exodus-redemption word: YHWH came to do for them what he did in Egypt, but they rejected it.</p>",
    "14": "<p><strong>velo za'aqu elai belibbam ki yeylellu al mishkevotam</strong>: 'They do not cry to me from their hearts; they merely howl on their beds.' The distinction between genuine prayer and ritual howling is one of Hosea's sharpest observations. <em>Za'aq</em> (cry out) from the <em>lev</em> (heart) = authentic petition; <em>yeylellu</em> (they howl/wail) on their beds is emotional expression without theological engagement. They howl for grain and wine — physical provision — but do not address the covenant God who alone can give. 'They gash themselves' (<em>yitgoredu</em>) — practices associated with Baal worship (1 Kgs 18:28). Their religious activity is Baal-inflected even in distress.</p>",
    "15": "<p><strong>va'ani yasarti chizaqti zero'otam va'elay yachashvu ra</strong>: 'I trained and strengthened their arms, yet they devise evil against me.' <em>Yasar</em> (train, discipline, instruct) combined with <em>chizaq</em> (strengthen) — YHWH's investment in forming Israel as a nation capable of covenant life. The arms he strengthened are now directed against him in evil plotting (<em>yachashvu ra</em>). This is the covenant ingratitude that Hosea makes concrete: the very capacities YHWH developed in Israel are used to plan evil against him. It echoes the Deuteronomic warning that prosperity would lead to forgetting YHWH (Deut 8:11-18) — the trained arms forget their trainer.</p>",
    "16": "<p><strong>yashuvun lo al-al hayah kequeshet remiyah</strong>: 'They return, but not to the Most High; they are like a treacherous bow.' <em>Lo al-al</em> (not to the Most High) — they return to something, but not to YHWH. The <em>qeshet remiyah</em> (treacherous bow, deceitful bow) is the bow that fails when you draw it — either not flexible enough or too flexible, so it shoots inaccurately. Israel is a weapon that cannot be relied upon, always veering away from the intended target. The same image appears in Ps 78:57: 'they were turned aside like a treacherous bow.' Their princes fall by the sword; their tongue's arrogance brings 'mockery in Egypt' (<em>laeg beEretz Mitzraim</em>) — the very nation they ran to for help witnesses their humiliation.</p>"
  },
  "8": {
    "1": "<p><strong>el chikkekha shofar ka-nesher al beit YHWH</strong>: 'Set the trumpet to your lips! An enemy swoops like an eagle against the house of the LORD.' The <em>shofar</em> (trumpet) blast announces imminent invasion. The eagle (<em>nesher</em>) swooping against the house of YHWH is the covenant curse of Deut 28:49: 'The LORD will bring a nation against you from far away, from the end of the earth, like an eagle swooping down.' What follows in Deut 28:50-68 is the detailed covenant curse that Hosea applies to the Assyrian invasion. 'They have transgressed my covenant and rebelled against my law' (<em>torati</em>) — the two covenant instruments (covenant and Torah) are named as the basis for the judgment announced.</p>",
    "2": "<p><strong>li yiz'aqu Elohai yedanucha Yisrael</strong>: 'Israel cries out to me, My God, we know you — we are Israel!' The community claims covenant knowledge — <em>yedanucha</em> (we know you) — in the moment of crisis, but Hosea's entire context shows this knowledge is superficial. <em>Da'at Elohim</em> (knowledge of God) is the covenant relationship's interior content, not merely recognition; 4:1 says 'there is no faithfulness, no steadfast love, and no knowledge of God in the land.' Claiming covenant identity ('we are Israel') while lacking its substance is the religious crisis Hosea diagnoses. The appeal to YHWH in crisis without the corresponding covenant life is the contradiction the book exposes.</p>",
    "3": "<p><strong>zenavh Yisrael tov oyev yirdefenu</strong>: 'Israel has thrown away what is good; an enemy will pursue him.' <em>Zenavh</em> (throw away, reject with disgust) + <em>tov</em> (what is good) — the good that Israel rejects is the covenant relationship, Torah, and YHWH's way of life. The consequence is automatic: rejection of the good produces pursuit by the enemy. This is the covenant logic of Leviticus 26 and Deuteronomy 28: rejection of YHWH results in pursuit by enemies. The brevity of v3 gives it aphoristic weight — a one-line summary of covenant theology: reject the good, be pursued by evil.</p>",
    "4": "<p><strong>hem himliku velo mimeni hisiru velo yadata</strong>: 'They have installed kings, but not by my authority; they have set up princes without my approval.' The northern kingdom's political history was marked by self-appointed kings (the sequence of usurpers from Jeroboam II onward). YHWH's authority over kingship — established in Deuteronomy 17 and exercised through prophetic anointing (1 Sam 9; 1 Kgs 1) — has been bypassed. With their silver and gold they made idols (<em>atzabbim</em>), 'so that he might be cut off' (<em>lema'an yikaret</em>) — the idol manufacture is the means of their own covenant cutting-off. The word for 'cut off' (<em>karat</em>) is the covenant-making term's dark inverse: the very relationship that was <em>karat</em> (cut, established) in covenant is now <em>karat</em> (cut off) by apostasy.</p>",
    "5": "<p><strong>zanach eglekh Shomron charah api bam</strong>: 'Your calf-idol is rejected, O Samaria; my anger burns against them.' The golden calf at Bethel/Samaria was erected by Jeroboam I (1 Kgs 12:28-29) as a religious alternative to Jerusalem, with the words: 'Here are your gods, O Israel, who brought you up out of Egypt.' Hosea's refutation is exegetical: 'How long before they are capable of innocence?' (<em>ad matai lo yukhal nezakion</em>) — innocence (<em>naqah</em>, purity, being cleared of guilt) is the covenantal goal that the idol-worshipping northern kingdom cannot achieve. The question implies that purity is possible but perpetually deferred by their apostasy.</p>",
    "6": "<p><strong>ki miYisrael vehu charash asahu vehu lo Elohim</strong>: 'For it comes from Israel! A craftsman made it; it is not God.' The theological argument against the calf-idol is anthropological: it was made by a craftsman (<em>charash</em>), it comes from Israel's own hands, therefore it cannot be God. This is Hosea's version of the idol-polemic developed more fully in Isaiah 44:9-20 and Psalm 115:4-8. 'The calf of Samaria will be shattered into pieces' (<em>shivvim yihyeh eghel Shomron</em>) — <em>shivvim</em> (splinters, chips) is the ignominious end of the thing they thought was their god.</p>",
    "7": "<p><strong>ki ruach yizre'u vesuphah yiqtzoru</strong>: 'For they have sown the wind and shall reap the whirlwind.' One of the OT's great aphoristic formulations. <em>Ruach</em> (wind, breath, spirit) sown produces <em>suphah</em> (whirlwind, hurricane) reaped — the principle of proportional, intensified consequences. Sowing something insubstantial (wind) produces not a harvest of wind but a harvest exponentially more destructive than the sowing. 'The stalk has no bud; it will produce no flour' — the agricultural futility extends the metaphor: their activity (sowing) produces not just nothing but escalating disaster. Paul applies this agricultural consequence principle to the moral life (Gal 6:7-8: 'you reap what you sow').</p>",
    "8": "<p><strong>nivla Yisrael attah hayu vagoyim kivli yechetz lahem</strong>: 'Israel is swallowed up; they are now among the nations like a worthless piece of pottery.' <em>Nivla</em> (swallowed up) — the same word Lamentations uses of the city swallowed by enemies (Lam 2:5). The worthless vessel (<em>keli ein chefetz</em>, a vessel in which there is no pleasure/desire) is the pottery that has lost its function. Israel's purpose was to be a vessel of divine blessing among nations; now they are scattered among them as a broken, unwanted pot.</p>",
    "9": "<p><strong>ki hem alu Ashur pere boded lo lahem</strong>: 'For they have gone up to Assyria — Ephraim is like a wild donkey going off alone; they have hired lovers.' The <em>pere</em> (wild donkey) is the symbol of wild, untameable self-direction — cf. Gen 16:12 (Ishmael will be like a wild donkey among men). The wild donkey that wanders alone contrasts with the domesticated animal that serves in community. Israel has gone alone (<em>boded</em>) to seek foreign alliances — 'hired lovers' (<em>mehanim ahavim</em>) — the covenant prostitution metaphor: paying foreign powers for the 'love' (alliance, protection) that YHWH alone legitimately provides.</p>",
    "10": "<p><strong>gam ki yiskor bagovim attah aqabbetzem</strong>: 'Even though they hire allies among the nations, I will now gather them in.' The divine gathering (<em>qabbetz</em>) that Israel seeks by hiring allies will come — but as judgment, not rescue. <em>Vayachelu me'at mas'et melekh sarim</em>: 'They will begin to diminish under the burden of king and princes' — the very foreign powers they paid for protection will burden them instead. The irony of covenant judgment: the thing Israel pursued for salvation becomes the instrument of its diminishment.</p>",
    "11": "<p><strong>ki hirbah Efraim mizbechot lachto</strong>: 'Since Ephraim has multiplied altars for sinning, those altars serve only to produce more sin.' The multiplication of cult sites (<em>mizbeachot</em>) that was supposed to multiply worship instead multiplies sin. This is the idolatry spiral: each additional altar is an additional occasion for transgression rather than an additional means of approaching YHWH. The means designed for righteousness become, when perverted, engines of corruption — the altar built for sin produces nothing but more sin.</p>",
    "12": "<p><strong>ichtov lo ribevo torati kemozar nechshavu</strong>: 'Though I wrote for him the great things of my law, they were treated as something foreign.' The written Torah — YHWH has <em>katav</em> (written) the ten thousand things (<em>ribevo</em>) of his instruction — is treated as <em>zar</em> (strange, foreign). The Torah given specifically to Israel is experienced by them as alien, belonging to another people. This is the covenant paradox: the most intimate divine self-disclosure (written law, personal instruction) is received as if it were someone else's document. The book (<em>ketav</em>) that should be the dearest possession is treated as an imposition.</p>",
    "13": "<p><strong>zivchei chabai yizbechu vasar vayochelu YHWH lo ratzam</strong>: 'They offer their sacrificial meat and eat it, but the LORD takes no pleasure in them.' The word <em>chabai</em> (my love gifts? my sacrificial gifts) is a hapax — possibly referring to 'love offerings' or sacrifices with a relational connotation. The sacrifices are performed correctly by external standards, but YHWH takes no pleasure (<em>lo ratzam</em>) — the same formula used of Israel's rejected worship in Amos 5:21-22. 'Now he will remember their iniquity and punish their sins; they will return to Egypt' — returning to Egypt (<em>Mitzraim yashuvun</em>) is the ultimate covenant reversal: the exodus undone, back to the starting point of slavery.</p>",
    "14": "<p><strong>vayishkach Yisrael et oseihu vayiven heichalot</strong>: 'For Israel has forgotten his Maker and built temples.' <em>Oseihu</em> (his Maker) — the creator-creature relationship is the bedrock of covenant; to forget the Maker is to lose the interpretive framework for everything. They substitute <em>heichalot</em> (palaces/great temples) for the relationship with the One who made them. Judah is also indicted: 'multiplied fortified cities' (<em>hirbah arim beturot</em>) — trust in military infrastructure rather than in YHWH. 'But I will send fire upon his cities; it will devour his strongholds' — the fire of judgment consumes the very fortifications they built as alternatives to covenant trust.</p>"
  },
  "9": {
    "1": "<p><strong>al tismach Yisrael al gil kamimim</strong>: 'Do not rejoice, Israel, as other peoples do.' The prohibition against rejoicing at harvest festivals is counterintuitive: harvest was the occasion for covenant celebration (Deut 16:13-15). But Israel's harvest joy is corrupted: 'you have loved the harlot's wage (<em>etnan zonah</em>) on every threshing floor' — the threshing floor where grain is processed has become the site of cultic prostitution associated with Baal fertility worship. The very place of provision is contaminated by the mode of seeking provision.</p>",
    "2": "<p><strong>hagoren vehayeqev lo yir'em</strong>: 'The threshing floor and wine press will not provide for them.' The covenantal reversal: the agricultural infrastructure that Baalism claimed to supply will now fail to provide. <em>Vehayayin yechash bah</em> (and the new wine will disappoint her) — <em>kachash</em> is the verb for lying and treachery; the new wine will 'lie' to them, prove false to its promise. The Baal cult promised fertility; YHWH announces its failure. The disappointment of the harvest is the theological argument against Baal in action.</p>",
    "3": "<p><strong>lo yeshvu be'Eretz YHWH</strong>: 'They will not remain in the LORD's land.' The land belongs to YHWH; residence there is conditional on covenant faithfulness (Lev 25:23; 26:33-38). To be expelled from the land is to be expelled from YHWH's residential domain. 'Ephraim will return to Egypt, and in Assyria they will eat unclean food' — the two exile destinations (Egypt and Assyria) bookend the historical directions of exile; the unclean food reflects the impossibility of maintaining covenant purity outside the land.</p>",
    "4": "<p><strong>lo yiseku laYHWH yayin</strong>: 'They will not pour out wine offerings to the LORD.' The <em>nesekh</em> (libation) and <em>zevachim</em> (sacrifices) that constitute covenant worship will be impossible in exile — no temple, no proper altar. 'Like mourner's bread (<em>lechem onen</em>), those who eat it will be defiled' — food associated with mourning was ritually unclean (Num 19:14; Ezek 24:17). The entire food system in exile is contaminated by death-uncleanness; even provision of food cannot be received as covenant blessing when outside the covenant land.</p>",
    "5": "<p><strong>mah ta'asu leyom mo'ed uleyom chag YHWH</strong>: 'What will you do on the day of the appointed festival, on the day of the LORD's feast?' The rhetorical question forces the exiles to imagine the festival calendar continuing without them. The <em>mo'ed</em> (appointed time/festival) and <em>chag</em> (feast) were the covenant markers of Israel's calendar — Passover, Pentecost, Tabernacles. In exile, these days will arrive without the community being able to celebrate. The question is not about logistical planning but theological confrontation: the festivals that should unite them to YHWH will come and find them absent.</p>",
    "6": "<p><strong>ki hinnam halchu mishod Mitzraim tiqabbetzem Mof tikbarem</strong>: 'For behold, they are fleeing to escape destruction; Egypt will gather them, and Memphis will bury them.' The refugees who flee to Egypt from Assyrian invasion find not salvation but burial. <em>Mof</em> (Memphis, the Egyptian capital) becomes a cemetery rather than a refuge. 'Their cherished silver, nettles will inherit it; thorns will be in their tents' (<em>ohaleihem</em>) — the personal dwellings that contained their precious things become overgrown ruins. This is the imagery of complete abandonment: the valued objects inherited by weeds.</p>",
    "7": "<p><strong>bau yemei hapequdah bau yemei hashillum yeda Yisrael</strong>: 'The days of reckoning have come; the days of recompense have arrived. Israel will know it.' <em>Pequddah</em> (visitation, reckoning, inspection) and <em>shillum</em> (recompense, payment) are the terms for covenant justice being executed. The phrase 'Israel will know it' (<em>yeda Yisrael</em>) is ironic: the people who claimed to 'know God' (8:2) and had the 'knowledge of God' demanded of them (4:6) will now know judgment. 'The prophet is a fool (<em>evil</em>), the man of the spirit is a madman' — either quoting Israel's dismissal of the prophets, or Hosea confessing the absurdity of his prophetic vocation in the community's eyes.</p>",
    "8": "<p><strong>tzofeh Efraim im-Elohai navi pach yaqosh al kol-derachav</strong>: 'Ephraim's watchman was to stand beside my God, but the prophet has become a fowler's trap on all his paths.' The <em>tzofeh</em> (watchman/sentinel) was the prophet's role in Ezekiel 3:17 and 33:7 — stationed to give early warning of spiritual danger. Hosea describes how the prophetic office has been perverted: instead of warning against the snares, the prophet has become the snare. <em>Pach yaqosh</em> (fowler's trap) — those who should protect the community from spiritual traps have become the mechanism of entrapment. The corruption of prophetic office is the deepest institutional failure.</p>",
    "9": "<p><strong>hiqiqu hishhitu kime Hagi'veah</strong>: 'They have gone deep into corruption, as in the days of Gibeah.' Gibeah was the site of the horrific crime of Judges 19-21 — the gang rape and murder of the Levite's concubine that led to the near-extinction of Benjamin. It was the nadir of the judges period, used as a byword for moral atrocity. To say northern Israel has sunk as deep as Gibeah is to locate their sin at the worst point of Israelite history. 'God will remember their iniquity; he will punish their sins' — divine forensic memory leading to enacted judgment.</p>",
    "10": "<p><strong>kagavim bamidbar matzati Yisrael</strong>: 'I found Israel like grapes in the wilderness.' The discovery of grapes in a desert is the image of startling, unexpected preciousness — Israel was found in an unlikely place (the wilderness of the exodus) and was delightful to YHWH like the first ripe fruit of the fig tree. This is the positive counterpart to the accusation: the covenant relationship had a pure, precious beginning. 'But when they came to Baal-peor, they consecrated themselves to the shameful thing' — Baal-peor (Num 25:1-9) is the paradigmatic apostasy, the first significant covenant breach in Canaan. From found-like-grapes to devoted-to-shame: the trajectory of fall from pristine covenant relationship.</p>",
    "11": "<p><strong>Efraim kaof yituf kevodo mizzevilada umibetten umihara</strong>: 'As for Ephraim, their glory will fly away like a bird — no birth, no pregnancy, no conception.' <em>Kevod</em> (glory) departing like a bird — the same departure of glory that Ezekiel describes from the temple (Ezek 10). The trilogy of reproductive futility (no birth, no pregnancy, no conception — in reverse order of development) represents complete demographic extinction. Ephraim's 'glory' was its population, military strength, and dynastic continuation; all of this flies away. The reversal of the Abrahamic promise (multiply and fill the land) is complete.</p>",
    "12": "<p><strong>ki im yegadelu et beneihem veshikaltim me'adam</strong>: 'Even if they raise their children, I will bereave them until not one is left.' The worst covenant curse: not merely childlessness but the death of children already raised. Parents invest years in children who are then taken. 'Truly, woe to them when I turn away from them' (<em>gam-oy lahem besuri mehem</em>) — the divine turning-away (<em>suri</em>) is more terrifying than active divine wrath; it is the withdrawal of presence that leaves the community entirely exposed to consequences without any divine buffer.</p>",
    "13": "<p><strong>Efraim kasher ra'iti leTzor shatul bena'veh</strong>: 'I saw Ephraim planted in a pleasant place, like Tyre.' Tyre was the ancient world's prosperous commercial city, famous for wealth derived from its position. Ephraim similarly occupies a pleasant, productive position. But 'Ephraim must now bring his children out to the slaughterer' (<em>el horegh yotzi banav</em>) — the pleasant position becomes the staging ground for slaughter. The prosperity that should lead to covenant gratitude leads instead to the children's deaths.</p>",
    "14": "<p><strong>ten lahem YHWH mah titen ten lahem rechem mashkil veshadadim tzovaim</strong>: 'Give them, O LORD — what will you give them? Give them a womb that miscarries and breasts that are dry.' This is one of the OT's most disturbing intercessory prayers — the prophet asks that the worst come quickly rather than slowly. A miscarrying womb and dry breasts means children cannot be born or sustained. The logic: if exile and slaughter await the children, better they not be born. It is a prayer of mercy through the form of a curse — asking for an end to birth so as to prevent the greater horror of children's deaths in the coming judgment.</p>",
    "15": "<p><strong>kol ra'atam beGilgal ki sham sene'tim</strong>: 'All their evil is at Gilgal — that is where my hatred for them took hold.' Gilgal was where Israel first camped after crossing the Jordan (Josh 5:10); later it became a cult center associated with apostasy (Amos 4:4; 5:5). The place of covenant beginning becomes the place where YHWH's hatred (<em>sina'tam</em>, I hated them) took hold. <em>Sina'</em> (hate) in the OT can mean covenantal rejection, the severing of the relationship — not emotional revulsion but covenant repudiation (cf. Mal 1:3: 'Esau I hated'). The irony: the place of covenant initiation becomes the place of its repudiation.</p>",
    "16": "<p><strong>hukah Efraim shorasham yavesh peri val ya'asu</strong>: 'Ephraim is struck down; their root is dried up and they will bear no fruit.' The agricultural metaphor: when the root (<em>shoresh</em>) dries up, there is no fruit, however vigorous the branches appeared. Ephraim's root in YHWH — the covenant relationship that was the source of its vitality — has been severed by apostasy; now visible fruitfulness ends. 'Even if they give birth, I will kill their dearly loved children' — the intensification of v12; even fertility that somehow persists will be cut off.</p>",
    "17": "<p><strong>yim'asem Elohai ki lo shamevu lo vihiyu novdim bagovim</strong>: 'My God will reject them because they did not listen to him; they will become wanderers among the nations.' <em>Ma'as</em> (reject, despise) is the covenant-rejection word — used of YHWH rejecting Saul (1 Sam 15:23), and here of YHWH rejecting Ephraim. <em>Novdim</em> (wanderers, vagabonds) echoes YHWH's curse on Cain: 'you will be a wanderer on the earth' (Gen 4:12, <em>na vaved</em> = unstable wanderer). Israel's post-exilic diaspora is the corporate form of the Cain curse. They become the paradigmatic homeless people — the people of the covenant scattered from the covenant land.</p>"
  },
  "10": {
    "1": "<p><strong>gepen boqeq Yisrael peri yeshaveh lo</strong>: 'Israel is a spreading vine that produces fruit for itself.' The vine metaphor (cf. Ps 80:8-16; Isa 5:1-7; Jer 2:21; Ezek 17:6) is used throughout the prophets for Israel's covenant relationship. A <em>boqeq</em> vine (spreading, luxuriant) should produce fruit for the vinedresser (YHWH) and the wider community; this vine produces fruit 'for itself' (<em>lo</em>) — self-directed fertility rather than covenant-directed fruitfulness. 'The more his fruit increased, the more altars he built' — prosperity produces more idolatry rather than more gratitude. <em>Keru'ot levavam</em> (divided/false heart): the vine's branching out is the image of a divided, unfaithful heart.</p>",
    "2": "<p><strong>chalaq libbam attah yeshamu</strong>: 'Their heart is deceitful; now they must bear their guilt.' <em>Chalaq</em> (smooth, slippery, divided) — the slick, divided heart is the source of covenant infidelity. 'He will demolish their altars and destroy their sacred pillars' (<em>yaaref mizbechotam yishoded matzevotam</em>) — YHWH acts as the covenant enforcer against the cultic infrastructure. The <em>matzevot</em> (sacred stone pillars) were originally acceptable (Gen 28:18; 31:13) but became associated with Canaanite worship and were condemned (Deut 16:22; Lev 26:1).</p>",
    "3": "<p><strong>ki attah yomeru ein melek lanu ki lo yare'anu et-YHWH</strong>: 'For now they say, We have no king, because we did not fear the LORD.' The irony of political crisis forcing theological honesty: they acknowledge that their lack of YHWH-fear is the cause of political instability. 'But what could a king do for us?' — even if they had a king, covenant disobedience would make him ineffective. The chain: fear of YHWH → covenant obedience → political stability. Without the first link, the chain breaks at every point. Their words are an inadvertent confession of covenant causality.</p>",
    "4": "<p><strong>dibberu devarim alot shav karat berit veparach kamosh mishpat</strong>: 'They make empty promises, swear false oaths, make covenants — so justice springs up like poisonous weeds in the furrows of a field.' The trio of verbal covenant violations: <em>devarim</em> (words, promises), <em>alot shav</em> (empty/false oaths), <em>berit</em> (covenant) — all the speech-acts of social and covenant life have been corrupted. When covenant speech becomes unreliable, justice (<em>mishpat</em>) becomes toxic — the very thing the covenant was supposed to produce grows like <em>rosh</em> (poisonous plant, hemlock) in the fields rather than like grain.</p>",
    "5": "<p><strong>legol'ot Shomron yaguru egel Beit-Aven</strong>: 'The people of Samaria will tremble because of the calf-idol of Beth-aven.' <em>Beit-Aven</em> (House of Wickedness) is Hosea's derisive renaming of Bethel (House of God) — the place where the golden calf was worshipped. The trembling (<em>yaguru</em>) before the idol is terror at the idol's coming destruction, not reverent worship. 'Its people will mourn over it, along with its priests who rejoiced in it' (<em>komarav alav yagilu alav</em>, his priests who rejoiced over it) — the joy of cultic success will be replaced by mourning when the idol is carried off to Assyria.</p>",
    "6": "<p><strong>gam oto leAshur yuval mincha lamelekh yarev</strong>: 'It will be carried off to Assyria as a gift for the great king.' <em>Melek yarev</em> (the great king/King Yareb) — probably a title for the Assyrian king, possibly Sargon II or Tiglath-Pileser III. The idol that was supposed to be Israel's strength goes as tribute to the very power it was supposed to protect Israel from. <em>Yevosh Yisrael mitzato</em> (Israel will be shamed because of its counsel) — the political counsel that sought Assyrian alliance and built the calf cult is doubly exposed as shameful: the idol becomes tribute, the nation becomes vassal.</p>",
    "7": "<p><strong>nidam Shomron malkah kaqetzef al pene maim</strong>: 'As for Samaria, her king will be swept away like a chip of wood on the water.' <em>Qetzef</em> (foam, chip of wood, splinter on the water) — something that floats briefly on the surface of turbulent water before being swept under. The Samaritan king who seemed substantial has the actual weight of flotsam. The image of kings and kingdoms as insubstantial debris on the flow of history is a consistent prophetic perspective: human political power is transient in YHWH's view.</p>",
    "8": "<p><strong>venishmadu bamot Aven chet Yisrael qotz vedardar ya'aleh al mizbehotam</strong>: 'The high places of Beth-aven, the sin of Israel, will be destroyed; thorns and thistles will grow up on their altars.' The thorns and thistles growing on ruined altars echo the Edenic curse of Gen 3:18 — the ground that was supposed to produce grain produces thorns. The cultic high places that Israel built as alternatives to YHWH's altar become overgrown ruins. 'They will say to the mountains, &ldquo;Cover us!&rdquo; and to the hills, &ldquo;Fall on us!&rdquo;' — this is cited directly in Luke 23:30 (Jesus to the weeping women) and Rev 6:16 (the sixth seal) as the cry of those facing ultimate judgment. The Hosea context is the collapse of Samaria; the NT application is the collapse of Jerusalem and the final judgment.</p>",
    "9": "<p><strong>mimei Hagi'veah chatata Yisrael</strong>: 'O Israel, you have sinned from the days of Gibeah.' For the second time (cf. 9:9) Hosea cites Gibeah as the reference point for Israel's ongoing moral nadir. 'There they have persisted' — the sin is not a historical relic but a continuing posture. 'Will not war overtake them in Gibeah?' — the battle fought at Gibeah (Judg 20) was devastating; a comparable war will come against the northern kingdom. The repetition of Gibeah in 9:9 and 10:9 shows that Hosea considers this the baseline example of what Israel's apostasy actually looks like when fully expressed.</p>",
    "10": "<p><strong>be'avvati ve'assrem veneassefu aleihem amim</strong>: 'It is my desire to discipline them; nations will be gathered against them to punish them for their double sin.' <em>Be'avvati</em> (in my desire/when I will it) — YHWH's disciplinary will is expressed through the nations assembled against Ephraim. 'Double sin' (<em>shtei avonot</em>) is disputed: possibly abandoning YHWH for the two calves (Bethel and Dan); possibly the twin sins of political apostasy (seeking foreign alliances) and religious apostasy (the calf cult). The instruments of discipline are historical nations acting under divine commission — the nations assembled are not random but divinely orchestrated.</p>",
    "11": "<p><strong>veEfraim eglah melumedah ohevet ladush</strong>: 'Ephraim is a trained heifer that loves to thresh grain.' Threshing was pleasant work for oxen — they trampled grain, could eat as they worked (Deut 25:4), and were not muzzled. Ephraim loved the easy work of covenant blessing without the burden of covenant obligation. 'But I have come to put a yoke on her fine neck' (<em>avarti al tov tzavvar'ah asim einol</em>) — the yoke represents covenant obligation (Matt 11:29-30 draws on this agricultural metaphor). The transition: from pleasant threshing to plowing (harder work, breaking new ground) is the shift from covenant enjoyment to covenant responsibility that Ephraim resisted.</p>",
    "12": "<p><strong>ziru lakem litzedaqah qitzru lefi chesed nirav lakhem nir</strong>: 'Sow righteousness for yourselves; reap covenant loyalty; break up your unplowed ground.' This verse is one of Hosea's central positive exhortations. <em>Tzedaqah</em> (righteousness) sown produces <em>chesed</em> (covenant loyalty/steadfast love) reaped — the agricultural metaphor for the covenant life. 'Break up your unplowed ground (<em>nir</em>)' — the fallow, hardened ground of the heart needs to be broken before seed can be planted. 'For it is time to seek the LORD' (<em>et lidrosh et-YHWH</em>) — <em>darash</em> (seek) is the covenant search term; the right response to the agricultural call is turning to YHWH. He will come and rain (<em>yoreh</em>) righteousness on you — the covenant relationship as provision.</p>",
    "13": "<p><strong>charastem resha avlata qatzartem achaltem peri chachash</strong>: 'But you have plowed wickedness, you have reaped injustice, you have eaten the fruit of lies.' The tragic inverse of v12's call: instead of sowing righteousness and reaping chesed, they sowed wickedness and reaped injustice. The agricultural sequence is reversed: wrong sowing → wrong harvest → consuming what is false. 'Because you have trusted in your own strength and in the multitude of your warriors' (<em>ki vatachta bedarkeha berov giborekha</em>) — the trust in military might rather than in YHWH is the root cause of the perverted agricultural sequence.</p>",
    "14": "<p><strong>veqam sha'on beamecha vekhol mibtazareiha yushodad</strong>: 'Therefore the tumult of war will arise against your people, and all your fortresses will be demolished.' <em>Sha'on</em> (tumult, crash, uproar of battle) — the covenant judgment arrives with the noise of warfare. 'As Shalman devastated Beth-arbel on the day of battle' — a historical atrocity used as the reference point, though the identity of Shalman is debated (possibly Shalmaneser V or a Transjordanian king). The mothers dashed to pieces with their children is the ultimate image of covenant curse fulfilled (cf. 13:16; Deut 28:53-57).</p>",
    "15": "<p><strong>ken asah lakem Beit-El mipene ra'at ra'atkem</strong>: 'So shall Bethel do to you because of your great wickedness.' The cult center responsible for the great sin becomes the instrument of judgment — it does to Israel what YHWH warned against. 'When morning comes, the king of Israel will be utterly swept away' (<em>nishmot nishmat melek Yisrael</em>) — the sudden end of the northern monarchy, which came swiftly with the fall of Samaria in 722 BCE. The dawn that should bring hope brings instead the obliteration of the royal house.</p>"
  },
  "11": {
    "2": "<p><strong>qereu lahem ken halchu mipaneihem labbe'alim yezabechu</strong>: 'The more they were called, the more they went away; they kept offering sacrifices to the Baals.' The calling (<em>qare'u</em>, they called/were called) that should have drawn Israel toward YHWH produced the opposite response — the more the covenant summons, the more the flight. This is the hardening dynamic of disobedience: repeated calls that are rejected do not soften the heart but harden it. The Baals received their sacrifices while YHWH's calls went unanswered — the inverted covenant response.</p>",
    "3": "<p><strong>va'anochi riggalti leEfraim qacham al zero'otav</strong>: 'Yet it was I who taught Ephraim to walk, taking him by the arms.' The divine father who teaches the child to walk (taking the arms for support) is one of the OT's most tender images of the YHWH-Israel relationship. <em>Riggalti</em> (I taught to walk, I trained the feet) is a rare verb describing the most intimate parental instruction. 'But they did not know that I healed them' (<em>lo yade'u ki refa'tim</em>) — the child who does not recognize the healer, taking the restored health as normal rather than as divine gift. Ingratitude as blindness: the healed do not know their healer.</p>",
    "4": "<p><strong>bechavlei adam emshachem ba'avot ahavah</strong>: 'I led them with cords of human kindness, with ropes of love.' <em>Chavel adam</em> (cords of a human being / cords of human kindness) and <em>avot ahavah</em> (ropes of love) — the divine leading is not coercion by force but the gentle drawing of covenant love. 'I was like someone who lifts the yoke from their jaws, and I bent down to them to feed them' — the image of an owner caring for a laboring animal, relieving the burden at the jaw and bending to provide food. The condescension of divine care — YHWH stoops to feed the one he has led — is the OT form of John 13:4-5 (Christ bending to wash feet).</p>",
    "5": "<p><strong>lo yashov el Eretz Mitzraim veAshur hu malko</strong>: 'He will not return to Egypt; the Assyrian will be his king, because they refused to repent.' The exile direction is Assyria, not Egypt — but the theological meaning is the same as a return to Egypt: subjugation under a foreign king. 'They refused to repent' (<em>ki me'enu lashuv</em>) — <em>shuv</em> (return/repent) is the covenant response Hosea has called for throughout; its refusal determines the exile. The exile is not arbitrary but is the direct consequence of refusing the return that would have prevented it.</p>",
    "6": "<p><strong>vechalah cherev be'arav vekiletah badav ve'achelah mimo'atzoteihem</strong>: 'A sword will rage against his cities; it will devour his strongholds and consume them because of their schemes.' The sword (<em>cherev</em>) devouring the fortified cities is the military expression of covenant judgment. The schemes (<em>mo'etzot</em>, counsels, plans) that trusted in foreign alliances rather than in YHWH are what the sword consumes — judgment falls precisely on the human strategies designed to avoid it.</p>",
    "7": "<p><strong>ve'ammi teluvim litshuvati</strong>: 'My people are determined to turn away from me.' <em>Teluvim litshuvati</em> is grammatically difficult: possibly 'bent on turning away from me' or 'hanging/suspended in returning to me.' The tension in 11:7-9 is the theological center of the chapter: the people's determination to turn away vs. YHWH's determination not to give them up (v8). 'Though they call out to the Most High (<em>el*Al*</em>), none of them will lift him up' — even when they call to YHWH, their calls are ineffective because they do not actually turn.</p>",
    "8": "<p><strong>ech eten'cha Efraim amasger'cha Yisrael</strong>: 'How can I give you up, Ephraim? How can I hand you over, Israel?' This verse is the emotional and theological peak of Hosea — the divine pathos at its most intense. The rhetorical questions are not requests for an answer but expressions of divine anguish over the covenant relationship. <em>Admah</em> and <em>Tzevoim</em> were cities destroyed with Sodom (Gen 14:2; Deut 29:23) — to make Ephraim like them would be their complete destruction. 'My heart turns (<em>nehpak libbi</em>) within me; all my compassions are stirred' (<em>nichamu nichumi</em>) — the divine heart literally 'overturns' at the prospect of Israel's total destruction. This is the OT's most concentrated expression of divine mercy wrestling with justice.</p>",
    "9": "<p><strong>lo e'eseh charon api lo ashuv leshachet Efraim</strong>: 'I will not carry out my fierce anger; I will not again destroy Ephraim.' The covenant-breaking people merit destruction, yet YHWH restrains the full expression of wrath. 'For I am God and not a human being' (<em>ki El anochi velo ish</em>) — the transcendence of divine love over human patterns of retribution. A human being given up on would stay given up on; YHWH's nature as God allows him to continue loving past what human love would endure. 'The Holy One (<em>qadosh</em>) in your midst' — holiness here is not primarily moral purity but the divine otherness that enables covenant faithfulness past all human expectation. This is the OT foundation for the NT's 'God is love' (1 John 4:8) — the divine nature, not human sentiment, is the ground of the inexhaustible mercy.</p>",
    "10": "<p><strong>acharei YHWH yelchu kearyeh yish'ag</strong>: 'They will walk after the LORD; he will roar like a lion. When he roars, his children will come trembling from the west.' The lion-roar is a sound of authority and summons (cf. Amos 3:8: 'the lion has roared; who will not fear?'). Here YHWH's roar summons the exiles home — the same power that sounded as judgment now sounds as restoration-call. The trembling (<em>yecheredu</em>) that was previously fear of judgment is transformed into the trembling of children rushing to their father. The scattering described throughout ch. 9-10 begins to reverse.</p>",
    "11": "<p><strong>yecherdu ketzipur miMitzraim ukeyonah me'Eretz Ashur</strong>: 'They will come trembling like birds from Egypt and like doves from Assyria.' The same dove that in 7:11 was senseless and directionless — flying to Egypt and Assyria in political panic — here comes from those same places back to YHWH. The return migration of the dove reverses the earlier flight. 'I will settle them in their homes' (<em>vehoshavtim al bateihem</em>) — the covenant promise of land-as-home is restored; the exile's dispossession is reversed by YHWH's direct resettlement.</p>",
    "12": "<p><strong>svavuni vekachash Efraim uvemiremah beit Yisrael</strong>: 'Ephraim has surrounded me with lies, and the house of Israel with deceit.' The surrounding (<em>svavuni</em>) of YHWH with lies — Israel's covenant words that profess relationship while enacting betrayal — is the final charge of ch. 11 before the historical reflection of ch. 12. 'But Judah still walks with God and is faithful with the Holy Ones' — the contrast between Judah and Ephraim in 11:12 is the moment of relative credit for Judah before Hosea returns to Jacob-history as the common ancestor's story.</p>"
  },
  "12": {
    "1": "<p><strong>Efraim ro'eh ruach veroddef qadim</strong>: 'Ephraim feeds on wind and pursues the scorching east wind all day.' The east wind (<em>qadim</em>, the <em>sirocco</em>) is the hot desert wind that desiccates vegetation and brings no nourishment. Feeding on wind and pursuing what cannot sustain is the image of Israel's foreign policy — seeking alliance with Assyria and Egypt (<em>shemen leMitzraim yuval</em>, oil sent to Egypt as tribute) rather than relying on the covenant provision of YHWH. The political activity is literally futile: pursuing the <em>sirocco</em> produces heat exhaustion, not sustenance.</p>",
    "2": "<p><strong>verivYHWH im Yehudah ulifqod al Ya'aqov kidrachav</strong>: 'The LORD has a case against Judah as well, and will punish Jacob according to his ways.' <em>Riv</em> (legal case, covenant lawsuit) is the prophetic legal form — YHWH as prosecutor presenting charges against the covenant people. The extension to Judah shows that the northern kingdom's failure is not unique; it reflects a pattern common to the whole people of Jacob. 'According to his deeds he will repay him' (<em>kima'alalav yashiv lo</em>) — the covenant principle of retributive proportionality: reward and punishment proportional to deeds.</p>",
    "3": "<p><strong>babbeten aqav et achiv uveavlato sarah im Elohim</strong>: 'In the womb he grasped his brother's heel, and in his strength he contended with God.' Jacob's two defining acts are cited: the heel-grasping (<em>aqav</em>) at birth (Gen 25:26, from which his name Jacob = heel-grasper is derived) and the wrestling with God (<em>sarah im Elohim</em>) at Peniel (Gen 32:28). The Jacob story is invoked as interpretive key for Ephraim's current condition: Jacob's identity was built on grasping and contending, but also on the transformation that came through the encounter with God. Hosea uses both aspects: the grasping (negative) and the wrestling-and-being-transformed (potential positive model for Israel's needed return).</p>",
    "4": "<p><strong>vayasar el malach vayukal yivk vayitchanen lo</strong>: 'He wrestled with the angel and prevailed; he wept and pleaded for the blessing.' The wrestling at Peniel (Gen 32:24-30) is interpreted by Hosea with the addition of weeping (<em>yivk</em>) and pleading (<em>yitchanen</em>): Jacob did not merely defeat the angel but prevailed through tears and supplication. This is Hosea's model for the Israel of his time: to prevail with God is not through power or political maneuvering but through the weeping, desperate prayer of the one who knows his only hope is divine blessing. 'At Bethel he found him, and there God spoke with him' — Bethel, which Hosea elsewhere condemns (4:15; 10:5), is also the site of genuine divine encounter (Gen 28:12-17).</p>",
    "5": "<p><strong>veYHWH Elohei Hatzvaot YHWH zikro</strong>: 'Even the LORD God of hosts — the LORD is his name to be remembered.' This parenthetical declaration of the divine name is Hosea's refocusing: the God who spoke with Jacob at Bethel is YHWH of armies, the transcendent sovereign. The 'name to be remembered' (<em>zikro</em>) connects to the covenant name-invocation — this God whose name Jacob claimed in his blessing (Gen 32:29-30) is the same YHWH whom Israel has abandoned. The memorial name (<em>zikr</em>, from the same root as <em>zakar</em>, remember) calls Israel to return to remembering who their God is.</p>",
    "6": "<p><strong>veattah beEloheicha tashuv chesed umishpat shemor</strong>: 'But as for you, return to your God; maintain covenant loyalty and justice, and wait for your God always.' The imperative triad: <em>shuv</em> (return/repent), <em>shemor chesed umishpat</em> (maintain covenant loyalty and justice), <em>qaveh el Elohekha tamid</em> (wait for your God always). <em>Chesed</em> (covenant loyalty/steadfast love) and <em>mishpat</em> (justice) are the two covenantal character marks Hosea most frequently calls for. <em>Qaveh</em> (wait with expectation, hope in) is the posture of covenantal patience — active expectant trust, not passive resignation (cf. Isa 40:31). The call is to imitate Jacob: weep, plead, wait — the posture of the contending-yet-dependent Jacob.</p>",
    "7": "<p><strong>Kena'an bekado moz'nei mirma</strong>: 'Ephraim is a trader who uses dishonest scales; he loves to take advantage of others.' <em>Kena'an</em> (Canaan) had become a byword for merchant/trader (cf. Job 40:30; Prov 31:24; Zeph 1:11). Hosea applies the term to Ephraim — they have become as Canaanite merchants, using false weights (<em>moz'nei mirma</em>, deceitful scales). The covenant people have taken on the commercial ethics of the people they were supposed to displace. <em>Ohev la'ashoq</em> (he loves to take advantage) — the love of exploitation as character disposition.</p>",
    "8": "<p><strong>vayomer Efraim ach asharthi matzati on li</strong>: 'But Ephraim says, Surely I have become rich; I have gained wealth for myself.' The self-congratulation of the successful merchant: wealth interpreted as self-justification. 'In all my hard work they will find no iniquity in me that is sin' — the claim that commercial success is moral evidence. This is the theology of prosperity as divine approval, one of the ancient world's (and the modern world's) most durable religious errors: if I am rich, I must be righteous. Hosea's entire book refutes this: covenant faithfulness to YHWH, not material prosperity, is the measure of covenantal standing.</p>",
    "9": "<p><strong>va'ani YHWH Eloheicha me'Eretz Mitzraim</strong>: 'But I, the LORD your God since the land of Egypt, will make you live in tents again, as in the days of the appointed festivals.' The divine counter-claim: YHWH's identity as the Exodus God is the refutation of Ephraim's self-sufficiency claim. The promised return to tent-dwelling (<em>ohel</em>) may allude to the wilderness tent-time of the Exodus, or to the Feast of Tabernacles (<em>Sukkot</em>) which commemorated wilderness living. Either way, YHWH will strip away the settled prosperity Ephraim credits to himself and restore the dependence-relationship of the wilderness generation.</p>",
    "10": "<p><strong>vedibbarti al hanevi'im ve'anochi chazon hirbeiti</strong>: 'I spoke through the prophets; I multiplied visions and gave parables through the prophets.' YHWH's communication with Israel has been comprehensive: prophets (<em>nevi'im</em>), visions (<em>chazon</em>), and parables (<em>dameh</em>, similitudes) are all instruments of divine speech. Hosea's own work is included in this catalog: his marriage to Gomer was itself a living parable (<em>dameh</em>). The multiplied means of communication makes Israel's deafness inexcusable — YHWH did not fail to speak but used every available medium.</p>",
    "11": "<p><strong>im Gilead aven ach shav hayu beggilgal shavarim zavachti</strong>: 'Is Gilead wicked? Yes, they are worthless! In Gilgal they sacrifice bulls; their altars will become like stone heaps on the furrows of the field.' Gilead (Transjordan) and Gilgal (cf. 9:15) are the two symbolic locations of sin — Gilead for its wickedness (possibly the Baal Peor incident, Num 25; or later crimes) and Gilgal for its cult sacrifice. The altars that should be means of covenant approach will become <em>galim</em> (stone heaps/cairns) — perhaps wordplay on <em>gilgal</em> (stone circle). Cult sites become rubble fields.</p>",
    "12": "<p><strong>vayivrach Ya'aqov sedeh Aram vaya'avod Yisrael be'ishah</strong>: 'Jacob fled to the country of Aram, and Israel served for a wife and tended flocks for a wife.' The Jacob-Laban narrative (Gen 29-31) is invoked: the patriarch fled and served for love, accepting labor as the price of the relationship. Hosea invokes this to contrast the Jacob who worked and waited with the Ephraim who exploits and takes. The ancestor served willingly for what he valued; his descendants exploit and steal to get what they want. The patriarchal humility of service has inverted into the Canaanite exploitation of v7.</p>",
    "13": "<p><strong>uvnavi he'elah YHWH et Yisrael miMitzraim</strong>: 'Through a prophet the LORD brought Israel up from Egypt, and through a prophet he was kept safe.' Moses is the prophet through whom YHWH accomplished both the exodus and the wilderness preservation. The prophetic mediation of redemption (Moses) and preservation (ongoing prophetic word in the wilderness) is the OT model for how YHWH works: through the prophetic voice. This verse justifies Hosea's own prophetic role — he stands in the Moses tradition as the voice through whom YHWH speaks covenant word to the people.</p>",
    "14": "<p><strong>hikhis Efraim tamrurim vedamav alav yitosh</strong>: 'Ephraim has provoked his LORD to the deepest anger; so he will leave Ephraim's bloodguilt on him and repay him for his contempt.' <em>Tamrurim</em> (bitternesses, the bitterest of provocations) is the strongest word Hosea uses for Israel's sin against YHWH. <em>Damim</em> (bloodguilt, blood-crimes) will be 'left on him' (<em>alav yitosh</em>) — not removed or covered by atoning sacrifice, but allowed to remain as the evidence for judgment. The covenant that should have provided atonement for bloodguilt is the very thing Ephraim has rejected, leaving the guilt exposed and unpurged. The chapter closes as a legal indictment: the bloodguilt stands, the contempt is repaid.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'hosea')
    merge_comm(existing, HOSEA)
    save_comm('mkt-original', 'hosea', existing)
    print('Hosea 7–12 mkt-original written.')

if __name__ == '__main__':
    main()
